"""Claude Code ``CLAUDE.md`` renderer.

Writes ``~/.claude/CLAUDE.md`` with the full memory bundle plus the
mandatory-first-action note. Layout matches the Codex global file but
the framing copy is slightly different — Claude Code surfaces this
file as a "user-level" instruction set and we lean on that framing.
"""

from __future__ import annotations

from pathlib import Path

from nerve.external_agents.registry import FileTarget
from nerve.external_agents.renderers.base import SECTION_DIVIDER, StyleRenderer


HEADER = """\
# CLAUDE.md — Generated by Nerve

This file is auto-rendered by Nerve and loaded by Claude Code at the
start of every session. It mirrors what Nerve-owned sessions get from
their system prompt: identity, user profile, hot memory, and workspace
conventions.

> ⚠️ **Do not edit by hand** — changes are overwritten on the next
> sync. Edit the source files in your Nerve workspace instead.
"""

FIRST_ACTION = """\
# Mandatory First Action — Call `session_context()`

Before answering anything in a fresh session, call the Nerve MCP tool
`session_context(topic="<what you're being asked to do>")`. It bundles:

- Recalled memories from memU, ranked against the topic
- Currently active skills
- Session metadata (id, source, current time)

Nerve-owned sessions receive this automatically as part of their
system prompt. Claude Code sessions don't, so the tool call is how you
get parity. Skip it and you'll be missing context that's already in
memory.
"""


class ClaudeCodeRenderer(StyleRenderer):
    """Render the Claude Code global ``CLAUDE.md`` bundle."""

    def render(self, target: FileTarget, *, workspace: Path) -> str:
        parts: list[str] = [HEADER.rstrip(), FIRST_ACTION.rstrip()]
        body = self._concat_includes(target, workspace, with_headings=True)
        if body:
            parts.append(body)
        parts.append(self._render_footer(workspace))
        return SECTION_DIVIDER.join(parts).rstrip() + "\n"

    def _render_footer(self, workspace: Path) -> str:
        return (
            "# Workspace\n\n"
            f"- **Path:** `{workspace}`\n"
            "- **Memory updates:** Save important facts with `memorize`; "
            "Nerve's daily maintenance cron handles dedup and pruning.\n"
            "- **Recall:** `memory_recall(query)` searches saved facts "
            "and past conversations.\n"
        )
